SELECT id FROM fd_department
WHERE his_id = #{hisId}
  AND (del_flag = 0 OR del_flag IS NULL)
  AND (
    tenant_id = #{tenantId}
    OR tenant_id IS NULL OR TRIM(tenant_id) = ''
  )
ORDER BY CASE WHEN tenant_id = #{tenantId} THEN 0 ELSE 1 END, id ASC
LIMIT 1

SELECT id FROM fd_supplier
WHERE his_id = #{hisId}
  AND (del_flag = 0 OR del_flag IS NULL)
  AND (
    tenant_id = #{tenantId}
    OR tenant_id IS NULL OR TRIM(tenant_id) = ''
  )
ORDER BY CASE WHEN tenant_id = #{tenantId} THEN 0 ELSE 1 END, id ASC
LIMIT 1

